    println!("Name length (via C strlen): {}", record.name_len_c().unwrap());

    // Modify the record
    record.set_value(99.9);
    record.set_name("sensor_beta").expect("Failed to set name");
    println!("Modified: {:?}", record);

    // Create a chain
